import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import axios from 'axios';
import '../styles/HomePage.css';

function HomePage({ user, onLogout }) {
  const navigate = useNavigate();
  const [searchQuery, setSearchQuery] = useState('');

  const handleLogout = () => {
    onLogout();
    navigate('/');
  };

  const handleSearch = (e) => {
    e.preventDefault();
  };

  return (
    <div className="full-page">
      <header className="header">
        <h1>TaskFlow</h1>
        <form className="search-form" onSubmit={handleSearch}>
          <input
            type="text"
            className="search-bar"
            placeholder="Search tasks..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
          />
        </form>
        <div className="auth-buttons">
          {user ? (
            <>
              <span className="user-name">Welcome, {user.name}</span>
              <button className="btn btn-secondary" onClick={() => navigate('/boards')}>
                My Boards
              </button>
              <button className="btn btn-danger" onClick={handleLogout}>
                Logout
              </button>
            </>
          ) : (
            <>
              <Link to="/login" className="btn btn-secondary">
                Login
              </Link>
              <Link to="/signup" className="btn btn-primary">
                Sign Up
              </Link>
            </>
          )}
        </div>
      </header>

      <div className="page-content">
        <div className="home-container">
          <div className="hero-section">
            <h2>Welcome to TaskFlow</h2>
            <p>Organize your tasks, collaborate with your team, and boost productivity</p>
            {!user && (
              <div className="cta-buttons">
                <Link to="/signup" className="btn btn-primary btn-lg">
                  Get Started
                </Link>
                <Link to="/login" className="btn btn-secondary btn-lg">
                  Sign In
                </Link>
              </div>
            )}
          </div>

          <div className="features-section">
            <h3>Features</h3>
            <div className="features-grid">
              <div className="feature-card">
                <h4>Easy Task Management</h4>
                <p>Create, organize, and manage your tasks with an intuitive interface</p>
              </div>
              <div className="feature-card">
                <h4>Drag and Drop</h4>
                <p>Move tasks between To Do, Ongoing, and Done sections seamlessly</p>
              </div>
              <div className="feature-card">
                <h4>Real-time Collaboration</h4>
                <p>Work with your team in real-time using WebSocket technology</p>
              </div>
              <div className="feature-card">
                <h4>Due Date Management</h4>
                <p>Set and track due dates for your tasks with calendar view</p>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default HomePage;
